#include <iostream>
#include <vector>
#include <omp.h>

void scan(const int* input, int* output, int n) {
    output[0] = 0;
    int nthreads;
    std::vector<int> partial_sums;

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        int sum = 0;

        #pragma omp single
        {
            nthreads = omp_get_num_threads();
            partial_sums.resize(nthreads + 1, 0);
        }

        int chunk_size = (n + nthreads - 1) / nthreads;
        int start = tid * chunk_size;
        int end = (start + chunk_size) > n ? n : (start + chunk_size);

        for (int i = start; i < end; i++) {
            sum += input[i];
            output[i + 1] = sum;
        }

        partial_sums[tid + 1] = sum;

        #pragma omp barrier

        int offset = 0;
        for (int i = 0; i <= tid; i++) {
            offset += partial_sums[i];
        }

        for (int i = start; i < end; i++) {
            output[i + 1] += offset;
        }
    }
}

int main() {
    int n;
    std::cin >> n;
    std::vector<int> input(n);
    for (int i = 0; i < n; i++) {
        std::cin >> input[i];
    }
    std::vector<int> output(n + 1);

    scan(input.data(), output.data(), n);

    for (int i = 0; i <= n; i++) {
        std::cout << output[i] << std::endl;
    }
    return 0;
}
